function downloadCSV(){
  var now=new Date();
  var dateStr=now.toLocaleDateString('de-DE',{day:'2-digit',month:'2-digit',year:'numeric'});
  var ref='GG-'+now.getFullYear()+'-'+String(now.getMonth()+1).padStart(2,'0')+String(now.getDate()).padStart(2,'0')+'-'+String(Math.floor(Math.random()*9000)+1000);
  var ls=_pdfData.ls, co=_pdfData.co, totalVE=_pdfData.totalVE;
  var net=ls.reduce(function(a,b){return a+b.sub;},0);
  var vat=net*0.19, sh=totalVE===1?4.99:0, total=net+vat+sh;
  var rows=[
    ['Gentle Gin B2B Bestellung'],
    ['Referenz',ref],
    ['Datum',dateStr],
    ['HÃ¤ndler',co],
    [],
    ['Produkt','SKU','VE (Kartons)','Staffel','Rabatt %','EK pro VE','Gesamt Netto']
  ];
  ls.forEach(function(l){
    var prod=PRODS.find(function(p){return p.n===l.n&&p.s===l.s;});
    rows.push([
      l.n+' '+l.s,
      prod?prod.id:'',
      l.qty,
      l.tier,
      l.d>0?(l.d*100).toFixed(0)+'%':'0%',
      (l.ek*6*(1-l.d)).toFixed(2).replace('.',',')+'â‚¬',
      l.sub.toFixed(2).replace('.',',')+'â‚¬'
    ]);
  });
  rows.push([]);
  rows.push(['','','','','','Netto',net.toFixed(2).replace('.',',')+'â‚¬']);
  rows.push(['','','','','','USt. 19%',vat.toFixed(2).replace('.',',')+'â‚¬']);
  rows.push(['','','','','','Versand',sh>0?sh.toFixed(2).replace('.',',')+'â‚¬':'kostenlos']);
  rows.push(['','','','','','Gesamt Brutto',total.toFixed(2).replace('.',',')+'â‚¬']);

  // BOM for Excel UTF-8
  var csv='\uFEFF'+rows.map(function(r){
    return r.map(function(v){
      var s=String(v===undefined||v===null?'':v);
      if(s.indexOf(',')>-1||s.indexOf('"')>-1||s.indexOf('\n')>-1) s='"'+s.replace(/"/g,'""')+'"';
      return s;
    }).join(';');
  }).join('\r\n');

  var blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});
  var url=URL.createObjectURL(blob);
  var a=document.createElement('a');
  a.href=url; a.download='GentleGin_Bestellung_'+ref+'.csv';
  document.body.appendChild(a); a.click();
  document.body.removeChild(a);
  setTimeout(function(){URL.revokeObjectURL(url);},5000);
}

function openLB(id){
  var p=PRODS.find(function(x){return x.id===id;});
  if(!p) return;
  document.getElementById('lb-img').src='data:image/png;base64,'+IMGS_FULL[id];
  document.getElementById('lb-tag').textContent=p.d;
  document.getElementById('lb-name').textContent=p.n;
  document.getElementById('lb-sku').textContent=p.id+'  Â·  '+p.a+'  Â·  '+p.s;
  document.getElementById('lb-ean-val').textContent=p.ean||'';
  document.getElementById('lb-uvp').textContent=f(p.u);
  document.getElementById('lb-uvp-sub').textContent=(LANG==='en'?'incl. VAT Â· recommended retail price':'inkl. MwSt. Â· empfohlener Verkaufspreis');
  document.getElementById('lb-uvp-label').textContent=(LANG==='en'?'RETAIL PRICE (RRP)':'UVP ENDKUNDE');
  document.getElementById('lb').classList.add('vis');
  document.body.style.overflow='hidden';
}
function closeLB(){
  document.getElementById('lb').classList.remove('vis');
  document.body.style.overflow='';
}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeLB();});

